module multi_pipe_8bit
(
    input clk,
    input rst_n,
    input mul_en_in,
    input mul_a,
    input mul_b,
    output reg mul_en_out,
    output mul_out
);

    parameter MUL_WIDTH = 8;
    reg [7:0] mul_a_reg, mul_b_reg;
    reg [15:0] mul_out_reg;
    reg [15:0] partial_sum [7:0];

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            mul_a_reg <= 8'b0;
            mul_b_reg <= 8'b0;
            mul_out_reg <= 16'b0;
            partial_sum <= '{default: 16'b0};
            mul_en_out <= 1'b0;
        end else begin
            if (mul_en_in) begin
                mul_a_reg <= mul_a;
                mul_b_reg <= mul_b;
            end

            for (int i = 0; i < MUL_WIDTH; i++) begin
                if (mul_b_reg[i]) begin
                    partial_sum[i] <= mul_a_reg << i;
                end else begin
                    partial_sum[i] <= 16'b0;
                end
            end

            mul_out_reg <= partial_sum[0] + partial_sum[1] + partial_sum[2] + partial_sum[3] +
                            partial_sum[4] + partial_sum[5] + partial_sum[6] + partial_sum[7];

            mul_en_out <= mul_en_in;
        end
    end

    assign mul_out = mul_out_reg;

endmodule
